import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axiosInstance from '../axiosConfig';
import { useAuth } from '../context/AuthContext';

const AdminDashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState(null);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) {
      navigate('/login');
      return;
    }
    if (user.role !== 'admin') {
      navigate('/entries');
      return;
    }
    fetchAdminData();
  }, [user]);

  const fetchAdminData = async () => {
    try {
      setLoading(true);
      const [statsRes, usersRes] = await Promise.all([
        axiosInstance.get('/api/admin/stats', {
          headers: { Authorization: `Bearer ${user.token}` },
        }),
        axiosInstance.get('/api/admin/users', {
          headers: { Authorization: `Bearer ${user.token}` },
        })
      ]);
      setStats(statsRes.data);
      setUsers(usersRes.data);
    } catch (error) {
      alert('Failed to load admin data');
      navigate('/entries');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteUser = async (userId) => {
    if (!window.confirm('Delete this user and all their entries?')) return;
    try {
      await axiosInstance.delete(`/api/admin/users/${userId}`, {
        headers: { Authorization: `Bearer ${user.token}` },
      });
      setUsers(users.filter(u => u._id !== userId));
    } catch (error) {
      alert('Failed to delete user');
    }
  };

  if (loading) return <div className="text-center mt-20">Loading...</div>;

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold text-teal-800 mb-6">Admin Dashboard</h1>

      {stats && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div className="bg-white rounded shadow p-6">
            <p className="text-gray-500 text-sm font-semibold">Total Users</p>
            <p className="text-4xl font-bold text-teal-600 mt-2">{stats.totalUsers}</p>
          </div>
          <div className="bg-white rounded shadow p-6">
            <p className="text-gray-500 text-sm font-semibold">Total Entries</p>
            <p className="text-4xl font-bold text-teal-600 mt-2">{stats.totalEntries}</p>
          </div>
        </div>
      )}

      <div className="bg-white rounded shadow p-6">
        <h2 className="text-2xl font-bold mb-4">Users</h2>
        <table className="min-w-full">
          <thead>
            <tr className="border-b">
              <th className="px-4 py-2 text-left">Name</th>
              <th className="px-4 py-2 text-left">Email</th>
              <th className="px-4 py-2 text-left">Role</th>
              <th className="px-4 py-2 text-center">Action</th>
            </tr>
          </thead>
          <tbody>
            {users.map((u) => (
              <tr key={u._id} className="border-b hover:bg-gray-50">
                <td className="px-4 py-2">{u.name}</td>
                <td className="px-4 py-2">{u.email}</td>
                <td className="px-4 py-2">
                  <span className={`px-2 py-1 rounded text-xs font-semibold ${
                    u.role === 'admin' ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-700'
                  }`}>
                    {u.role || 'user'}
                  </span>
                </td>
                <td className="px-4 py-2 text-center">
                  <button
                    onClick={() => handleDeleteUser(u._id)}
                    disabled={u.role === 'admin'}
                    className="bg-red-500 hover:bg-red-700 disabled:bg-gray-400 text-white px-3 py-1 rounded text-sm"
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminDashboard;
